void solve_SBBBL(Cube* cube) {
    ZZ_PROFILE_SCOPE(SolveSBBBL);
    uint8_t keyDown = cube->cube[53];
    uint8_t keyBack = cube->cube[44];
    uint8_t keyLeft = cube->cube[17];
    second_block_last_corner = find_corner(cube, keyDown, keyLeft, keyBack);
    second_block_last_edge_down = find_edge(cube, keyLeft, keyDown);
    second_block_last_edge_side = find_edge(cube, keyLeft, keyBack);

    // If the second block is already solved, there is nothing to do.
    if (second_block_last_corner == 51 &&
        second_block_last_edge_down == 11 &&
        second_block_last_edge_side == 7) {
        second_block_last_index = -1;
        strncpy(second_block_last_name, "SBBBL", sizeof(second_block_last_name) - 1);
        second_block_last_name[sizeof(second_block_last_name) - 1] = '\0';
        return;
    }

    second_block_last_index = get_BBF2L_Index(second_block_last_corner, second_block_last_edge_down, second_block_last_edge_side, 42, 6, X2_map, B2_LUT);
    strncpy(second_block_last_name, "SBBBL", sizeof(second_block_last_name) - 1);
    second_block_last_name[sizeof(second_block_last_name) - 1] = '\0';
    SBBBL_moves[second_block_last_index](cube);
}
